	// Create a test selector cache
	repo := NewPolicyRepository(nil, nil, nil)
	selectorCache := repo.GetSelectorCache()

	// Test with selector cache
	logger.LogEvaluation(ctx, policyKey, selectorCache, false)

	// Verify the logger is still functional
	assert.Equal(t, logrus.InfoLevel, logger.GetLogLevel())
}

