			Identity:         2000,
			DestPort:         443,
			InvertedPortMask: 0,
			Nexthdr:          6,
			TrafficDirection: trafficdirection.Egress.Uint8(),
		},
		{
			Identity:         3000,
			DestPort:         0,
			InvertedPortMask: 0,
			Nexthdr:          0,
			TrafficDirection: trafficdirection.Ingress.Uint8(),
		},
	}

	for _, key := range testCases {
		logger.LogEvaluation(ctx, key, selectorCache, true)
	}

	// Verify the logger is still functional
	assert.Equal(t, logrus.InfoLevel, logger.GetLogLevel())
