    'pkg/policy/audit_logger.go',
    'pkg/policy/audit_logger_test.go'
]

for filepath in files:
    with open(filepath, 'r') as f:
        content = f.read()

    print(f"\n=== Checking {filepath} ===")

    # Check package declaration
    if 'package policy' in content:
        print("✓ Package declaration found")
    else:
        print("✗ Missing package declaration")

    # Check imports
    if 'import' in content:
        print("✓ Import block found")
    else:
        print("✗ Missing import block")

    # Check for main structures
    if 'PolicyAuditLogger' in content:
        print("✓ PolicyAuditLogger type found")
    else:
        print("✗ Missing PolicyAuditLogger type")

    # Check for required functions
    required_funcs = ['LogDecision', 'LogEvaluation', 'NewPolicyAuditLogger']
    for func in required_funcs:
        if f'func' in content and func in content:
            print(f"✓ {func} function found")
        else:
            print(f"✗ Missing {func} function")

    # Check for test functions in test file
    if filepath.endswith('_test.go'):
        test_funcs = re.findall(r'func (Test\w+)\(', content)
        print(f"✓ Found {len(test_funcs)} test functions: {', '.join(test_funcs[:5])}...")

    # Check for balanced braces
    open_braces = content.count('{')
    close_braces = content.count('}')
    if open_braces == close_braces:
        print(f"✓ Balanced braces ({open_braces})")
    else:
        print(f"✗ Unbalanced braces: {{ {open_braces}, }} {close_braces}")

print("\n✓ Syntax validation complete")
